"""Unit tests for FineCalculator service."""import pytestfrom datetime import datetime, timedeltafrom src.config.fine_config import FineConfigurationfrom src.services.fine_service import FineCalculatorfrom src.models.loan import LoanRecordfrom src.collections.loan_collection import LoanCollectionclass TestFineCalculator:    """Test suite for FineCalculator."""    @pytest.fixture    def calculator(self):        return FineCalculator()    def test_calculate_fine_zero_days(self, calculator):        assert calculator.config.calculate_fine(0) == 0.0        assert calculator.config.calculate_fine(-5) == 0.0    def test_calculate_fine_first_tier(self, calculator):        # 3 days * 0.50 = 1.50        assert calculator.config.calculate_fine(3) == 1.50        # 7 days * 0.50 = 3.50        assert calculator.config.calculate_fine(7) == 3.50    def test_calculate_fine_second_tier(self, calculator):        # 10 days: (7*0.50) + (3*1.00) = 3.50 + 3.00 = 6.50        assert calculator.config.calculate_fine(10) == 6.50    def test_calculate_fine_third_tier(self, calculator):        # 35 days: (7*0.50) + (23*1.00) + (5*2.00) = 36.50        assert calculator.config.calculate_fine(35) == 36.50    def test_maximum_fine_cap(self, calculator):        fine = calculator.config.calculate_fine(1000)        assert fine == 100.00    def test_custom_configuration(self):        config = FineConfiguration(rate_tiers=[(1, 5, 1.00)], max_fine=50.00)        calc = FineCalculator(config)        assert calc.config.calculate_fine(3) == 3.00        assert calc.config.calculate_fine(6) == 0.0  # Not in any tier    def test_calculate_loan_fine(self, calculator):        # Create overdue loan        checkout = datetime.now() - timedelta(days=20)        loan = LoanRecord.create_loan("123", "M001", checkout)        # Force due date to be 10 days ago        loan.due_date = datetime.now() - timedelta(days=10)        fine = calculator.calculate_loan_fine(loan)        expected = calculator.config.calculate_fine(10)        assert fine == expected    def test_calculate_member_fines(self, calculator):        # Setup        loan_collection = LoanCollection()        member_id = "M001"        # Loan 1: overdue by 5 days        loan1 = LoanRecord.create_loan("111", member_id, datetime.now() - timedelta(days=20))        loan1.due_date = datetime.now() - timedelta(days=5)        loan_collection.add_loan(loan1)        # Loan 2: not overdue        loan2 = LoanRecord.create_loan("222", member_id, datetime.now() - timedelta(days=5))        loan2.due_date = datetime.now() + timedelta(days=10)        loan_collection.add_loan(loan2)        total = calculator.calculate_member_fines(member_id, loan_collection)        expected = calculator.config.calculate_fine(5)        assert total == expected